ncData.valueScript:
//====================================================================
  // Get data for millings
  //====================================================================

  // Variables
  let millings: ICT_tab_HardwareMillingLibrary[] = [];

  // Find all processings for the drawerbox (to each part)
  let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);

  // Find the drillings for the sidepanel
  processings.forEach((processing) => {
    if(processing.ProcessingLibrary == 'Milling'){
      let foundMillings = GlobalFunc.find_HardwareMilingLibrary(processing.ProcessingId!, 'BoxBtm');
      millings = millings.concat(foundMillings);
    }
  });

  //====================================================================
  // For each milling (insert the millings)
  //====================================================================

  millings.forEach(x => 
  {  
    // Position of the milling in graphics
    let PosX=0;
    let PosY=0;
    let PosZ=0;

    // Add Milling
    let Milling = this.addncout_Pocket();
    Milling.nc_TOOL="112";
    Milling.nc_Side=x.Side;
    Milling.nc_XA=x.XA(partSelf._dimx, partSelf, part2, posRel);
    Milling.nc_YA=x.YA(partSelf._dimz/2, partSelf, part2, posRel);
    Milling.nc_LA=x.BR(0, partSelf, part2, posRel);
    Milling.nc_BR=partSelf._dimz;
    Milling.nc_TI=x.TI(0, partSelf, part2, posRel);

    Milling.nc_RD=x.matrix_RD || 0;
    Milling.nc_KO=x.matrix_KO || "00";
    Milling.nc_T_='101';


    // Add drawing
    let drilling01 = partSelf.add3DElement('Milling01', Milling, PosX, PosY, PosZ, x.BR(0, partSelf, part2, posRel), x.TI(0, partSelf, part2, posRel), partSelf._dimz );
    drilling01.extrude('<svg><rect x="' + (x.XA(partSelf._dimx, partSelf, part2, posRel) - x.BR(0, partSelf, part2, posRel) / 2) + '" y="' + 0 + '" width="' + x.BR(0, partSelf, part2, posRel) + '" height="' + x.TI(0, partSelf, part2, posRel) + '" /></svg>', 'z');
  })

  //====================================================================
  // Get data for drillings
  //====================================================================

  // Variables
  let drillings: ICT_tab_HardwareDrillVertLibrary[] = [];

  // Find all processings for the drawerbox (to each part)
  processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);

  // Find the drillings for the sidepanel
  processings.forEach((processing) => {
    if(processing.ProcessingLibrary == 'DrillVertical'){
      let foundDrillings = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'BoxBtm');
      drillings = drillings.concat(foundDrillings);
    }
  });

  //====================================================================
  // For each drilling (insert the drillings)
  //====================================================================

  // drill for screwing the box side to the bottom shelf (right side)
  drillings.forEach(x => 
  {  
    // Position of the drill
    let PosX=partSelf._dimx - x.XA;
    let PosY=0;
    let PosZ=partSelf._dimz - x.YA;

    // Add Vertical Drill
    let DrillVert = this.addncout_DrillVert();
    DrillVert.nc_TOOL="102";
    DrillVert.nc_XA=partSelf._dimx - x.XA;
    DrillVert.nc_YA=x.YA;
    DrillVert.nc_TI=x.TI;
    DrillVert.nc_DU=x.DU;

    DrillVert.nc_BM = x.matrix_BM || "LS"
    DrillVert.nc_WI = x.matrix_WI ?? 0;
    DrillVert.nc_AB = x.matrix_AB ?? 1;
    DrillVert.nc_LA = x.matrix_LA ?? 0;
    DrillVert.nc_MI = x.matrix_MI ?? 0;
    DrillVert.nc_KO = x.matrix_KO || "00";
    DrillVert.nc_Side = "Top";  

    // Add drawing
    let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, x.DU, x.TI, x.DU );
    drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'y');
  })

  // drill for screwing the box side to the bottom shelf (left side)
  drillings.forEach(x => 
    {  
      // Position of the drill
      let PosX=x.XA;
      let PosY=0;
      let PosZ=partSelf._dimz - x.YA;

      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL="102";
      DrillVert.nc_XA=x.XA;
      DrillVert.nc_YA=x.YA;
      DrillVert.nc_TI=x.TI;
      DrillVert.nc_DU=x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";  

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, x.DU, x.TI, x.DU );
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'y');
    })

// Calcualte quantity of drills
let numberOfDrills = Math.floor(partSelf._dimx / 100);
let distance = Math.round((partSelf._dimx-140) / (numberOfDrills-1))
let actPos = 70;

// Cycle to insert the drills
for (let i = 1; i <= numberOfDrills; i++) {

  // Position of the drill
  let PosX=actPos;
  actPos+=distance;
  let PosY=0;
  let PosZ=posRel.z + part2._dimz/2;

  // Add Vertical Drill
  let DrillVert = this.addncout_DrillVert();
  DrillVert.nc_TOOL="102";
  DrillVert.nc_XA=PosX;
  DrillVert.nc_YA=partSelf._dimz - PosZ;
  DrillVert.nc_TI=partSelf._dimy;
  DrillVert.nc_DU=4;

  DrillVert.nc_BM = "LS"
  DrillVert.nc_WI = 0;
  DrillVert.nc_AB = 1;
  DrillVert.nc_LA = 0;
  DrillVert.nc_MI = 0;
  DrillVert.nc_KO = "00";
  DrillVert.nc_Side = "Top";  

  // Add drawing
  let drilling02 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, 4, partSelf._dimy, 4);
  drilling02.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + 2 + '" /></svg>', 'y');
}

//====================================================================
// Get data for drillings
//====================================================================

// Variables
let drillings: ICT_tab_HardwareDrillVertLibrary[] = [];

// Find all processings for the drawerbox (to each part)
let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);

// Find the drillings for the sidepanel
processings.forEach((processing) => {
  if(processing.ProcessingLibrary == 'DrillVertical'){
    let foundDrillings = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'BoxBtm');
    drillings = drillings.concat(foundDrillings);
  }
});

//====================================================================
// For each drilling (insert the drillings)
//====================================================================

// drill for screwing the box side to the bottom shelf (right side)
drillings.forEach(x => 
{  
  // Position of the drill
  let PosX=posRel.x + x.XA;
  let PosY=0;
  let PosZ=partSelf._dimz + x.YA;

  // Add Vertical Drill
  let DrillVert = this.addncout_DrillVert();
  DrillVert.nc_TOOL="102";
  DrillVert.nc_XA=PosX;
  DrillVert.nc_YA=-x.YA;
  DrillVert.nc_TI=x.TI;
  DrillVert.nc_DU=x.DU;

  DrillVert.nc_BM = x.matrix_BM || "LS"
  DrillVert.nc_WI = x.matrix_WI ?? 0;
  DrillVert.nc_AB = x.matrix_AB ?? 1;
  DrillVert.nc_LA = x.matrix_LA ?? 0;
  DrillVert.nc_MI = x.matrix_MI ?? 0;
  DrillVert.nc_KO = x.matrix_KO || "00";
  DrillVert.nc_Side = "Top";  

  // Add drawing
  let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, x.DU, x.TI, x.DU );
  drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'y');
})
